        console.log(1 != 1, 1 !== 1)""".stripMargin.trim,
      expected = """console.log(!1);
        console.log(!0, !0);
        console.log(!1, !1)""".stripMargin.trim,
      options = AllOff.copy(
        booleans = true,
        evaluate = true
      )
    )
  }

